/// @file neon_fp32_8x12.cpp
/// Auto-generated packed 8x12 FP32 NEON micro-kernel.
/// Generated by: tools/gen_neon_gemm.py
///   Mr=8, Nr=12, K_unroll=2
///   Register budget: 24 acc + 3 B + 2 A = 29 regs
///   1-pass (fits in 32 regs)

